-- GIG — CZŁONKOWIE (stan 2026-06-18, z docx). Uruchom RAZ w Supabase SQL Editor.
CREATE TABLE IF NOT EXISTS czlonkowie (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name TEXT NOT NULL UNIQUE, region TEXT, person TEXT, phone TEXT, email TEXT,
  address TEXT, website TEXT, description TEXT,
  status TEXT DEFAULT 'published' CHECK (status IN ('draft','published')),
  created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_czlonkowie_region ON czlonkowie (region, name);
ALTER TABLE czlonkowie ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "czl public read" ON czlonkowie;
CREATE POLICY "czl public read" ON czlonkowie FOR SELECT USING (status='published');
DROP POLICY IF EXISTS "czl admin all" ON czlonkowie;
CREATE POLICY "czl admin all" ON czlonkowie FOR ALL USING (auth.role()='authenticated');
